// Package assets embeds the committed, fingerprinted ui/goth distributable
// outputs and the generated asset manifest. The compiled CSS/JS under dist/ and
// manifest.json are GENERATED by the Node-gated asset build (ui/goth/tools) and
// are never hand-edited; edit the sources under assets/src and regenerate. A Go
// consumer of ui/goth needs only Go and these embedded bytes — never Node, npm,
// Alpine sources, or a bundler.
package assets

import (
	"embed"
	"io/fs"
)

//go:embed dist
var distFS embed.FS

// FS is the embedded, read-only asset filesystem. The embed RETAINS the dist/
// path segment, so served FS paths are "dist/<hashed>" rather than root-level.
// Serve it under the bundle AssetBasePath with
// sdk/foundation/web.NewStaticFileServer + WithAssetPrefix("dist/"); the "dist/"
// prefix is what the SDK server matches to apply immutable caching.
var FS fs.FS = distFS

// ManifestBytes is the committed, embedded manifest.json parsed by goth.New.
//
//go:embed manifest.json
var ManifestBytes []byte
